   133→  ];
   134→}
   135→
   136→/**
   137→ * Filter tasks visible within viewport bounds
   138→ */
   139→function filterVisibleTasks(
   140→  tasks: TaskRender[],
   141→  viewportBounds?: ViewportBounds
   142→): TaskRender[] {
   143→  if (!viewportBounds) return tasks;
   144→
   145→  const padding = 100;
   146→  const minX = viewportBounds.minX - padding;
   147→  const maxX = viewportBounds.maxX + padding;
   148→  const minY = viewportBounds.minY - padding;
   149→  const maxY = viewportBounds.maxY + padding;
   150→
   151→  return tasks.filter((task) => {
   152→    const taskStartX = task.startDay * pxPerDay;
   153→    const taskEndX = taskStartX + task.duration * pxPerDay;
   154→    const taskY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
