   188→    backgrounds.push({
   189→      trainIndex: i,
   190→      polygon: createRectPolygon(0, y1, totalWidth, y2),
   191→      isEven: i % 2 === 0,
   192→    });
   193→  }
   194→
   195→  return backgrounds;
   196→}
   197→
   198→function generateGridLines(
   199→  totalDays: number,
   200→  trainCount: number,
   201→  viewportBounds?: ViewportBounds
   202→): { horizontal: GridLine[]; vertical: GridLine[] } {
   203→  const totalWidth = totalDays * pxPerDay;
   204→  const totalHeight = trainCount * pxPerTrain;
   205→
   206→  const horizontal: GridLine[] = [];
   207→  const vertical: GridLine[] = [];
   208→
   209→  // Visible horizontal lines (train boundaries)
   210→  let minTrainIndex = 0;
   211→  let maxTrainIndex = trainCount;
   212→
   213→  if (viewportBounds) {
   214→    minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
