   256→      id: task.id,
   257→      polygon: createRectPolygon(x1, y1, x2, y2),
   258→      task,
   259→    };
   260→  });
   261→}
   262→
   263→function generateTaskLabels(
   264→  tasks: TaskRender[],
   265→  linearZoom: number,
   266→  maxLabels: number = 50
   267→): TaskLabel[] {
   268→  // Only show labels on tasks wide enough
   269→  const minWidthForLabel = 40 / linearZoom;
   270→  const filtered = tasks.filter((t) => t.duration * pxPerDay > minWidthForLabel);
   271→
   272→  // Sort by width (largest first) and take top N
   273→  const sorted = filtered
   274→    .sort((a, b) => b.duration - a.duration)
   275→    .slice(0, maxLabels);
   276→
   277→  return sorted.map((task) => {
   278→    const width = task.duration * pxPerDay;
   279→    const x = task.startDay * pxPerDay + width / 2;
   280→    const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   281→    const label = task.type.charAt(0).toUpperCase() + task.type.slice(1);
   282→
   283→    return {
   284→      position: [x, y] as [number, number],
   285→      text: label,
   286→      taskId: task.id,
   287→    };
   288→  });
   289→}
   290→
   291→function generateConflictGlows(tasks: TaskRender[]): EffectPolygon[] {
   292→  return tasks
   293→    .filter((t) => t.hasConflict)
   294→    .map((task) => {
   295→      const padding = 2;
   296→      const width = task.duration * pxPerDay;
   297→      const x1 = task.startDay * pxPerDay - padding;
   298→      const x2 = x1 + width + padding * 2;
   299→      const y1 = -task.trainIndex * pxPerTrain - CARD_PADDING + padding;
   300→      const y2 = y1 - CARD_HEIGHT - padding * 2;
   301→
   302→      return {
   303→        taskId: task.id,
   304→        polygon: createRectPolygon(x1, y1, x2, y2),
   305→      };
   306→    });
   307→}
   308→
   309→function generateFocusRing(
   310→  tasks: TaskRender[],
   311→  focusedTaskId: string | null
   312→): EffectPolygon | null {
   313→  if (!focusedTaskId) return null;
   314→
   315→  const task = tasks.find((t) => t.id === focusedTaskId);
   316→  if (!task) return null;
   317→
   318→  const padding = 3;
   319→  const width = task.duration * pxPerDay;
   320→  const x1 = task.startDay * pxPerDay - padding;
   321→  const x2 = x1 + width + padding * 2;
   322→  const y1 = -task.trainIndex * pxPerTrain - CARD_PADDING + padding;
   323→  const y2 = y1 - CARD_HEIGHT - padding * 2;
   324→
   325→  return {
   326→    taskId: task.id,
   327→    polygon: createRectPolygon(x1, y1, x2, y2),
   328→  };
   329→}
   330→
   331→function generateDependencyPaths(tasks: TaskRender[]): DependencyPath[] {
   332→  const taskMap = new Map(tasks.map((t) => [t.id, t]));
   333→  const paths: DependencyPath[] = [];
   334→
   335→  for (const task of tasks) {
   336→    if (task.predecessorId) {
   337→      const predecessor = taskMap.get(task.predecessorId);
   338→      if (predecessor) {
   339→        // From: right edge of predecessor
   340→        const fromX = (predecessor.startDay + predecessor.duration) * pxPerDay;
   341→        const fromY = -predecessor.trainIndex * pxPerTrain - pxPerTrain / 2;
   342→
   343→        // To: left edge of dependent
   344→        const toX = task.startDay * pxPerDay;
   345→        const toY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   346→
   347→        const midX = (fromX + toX) / 2;
   348→        const isSameRow = predecessor.trainIndex === task.trainIndex;
   349→
   350→        let path: [number, number][];
   351→        if (isSameRow) {
   352→          const offsetY = 8;
   353→          path = [
   354→            [fromX, fromY + offsetY],
   355→            [midX, fromY + offsetY + 5],
   356→            [toX, toY + offsetY],
   357→          ];
   358→        } else {
   359→          const controlOffset = Math.abs(toY - fromY) * 0.3;
   360→          path = [
   361→            [fromX, fromY],
   362→            [fromX + controlOffset, fromY],
   363→            [midX, (fromY + toY) / 2],
   364→            [toX - controlOffset, toY],
   365→            [toX, toY],
   366→          ];
   367→        }
   368→
   369→        paths.push({
   370→          path,
   371→          fromId: predecessor.id,
   372→          toId: task.id,
   373→        });
   374→      }
   375→    }
   376→  }
   377→
   378→  return paths;
   379→}
   380→
   381→// ─────────────────────────────────────────────────────────────
   382→// LAYER FACTORY
   383→// ─────────────────────────────────────────────────────────────
   384→
   385→export interface MicroLayerOptions {
   386→  tasks: TaskRender[];
   387→  trainCount: number;
   388→  totalDays?: number;
   389→  visible?: boolean;
   390→  opacity?: number;
   391→  linearZoom?: number;
   392→  viewportBounds?: ViewportBounds;
   393→  hoveredTaskId?: string | null;
   394→  selectedTaskId?: string | null;
   395→  focusedTaskId?: string | null;
   396→}
   397→
   398→/**
   399→ * Create MicroLayer (deck.gl layers) for detailed task visualization
   400→ *
   401→ * Returns an array of layers:
   402→ * - Row backgrounds
   403→ * - Grid lines
   404→ * - Conflict glows
   405→ * - Focus ring
   406→ * - Task cards
   407→ * - Task labels
   408→ * - Dependency lines
   409→ */
   410→export function createMicroLayers({
   411→  tasks,
   412→  trainCount,
   413→  totalDays = 365 * 10,
   414→  visible = true,
   415→  opacity = 1,
   416→  linearZoom = 3,
   417→  viewportBounds,
   418→  hoveredTaskId = null,
   419→  selectedTaskId = null,
   420→  focusedTaskId = null,
   421→}: MicroLayerOptions): Layer[] {
   422→  if (!visible) {
   423→    return [];
   424→  }
   425→
   426→  // Don't render labels during low opacity transitions
   427→  const showLabels = opacity >= 0.3;
   428→
   429→  // Filter to visible tasks
   430→  const visibleTasks = filterVisibleTasks(tasks, viewportBounds);
   431→
   432→  // Generate data
   433→  const rowBackgrounds = generateRowBackgrounds(trainCount, totalDays, viewportBounds);
   434→  const { horizontal: hGridLines, vertical: vGridLines } = generateGridLines(
   435→    totalDays,
   436→    trainCount,
   437→    viewportBounds
   438→  );
   439→  const taskPolygons = generateTaskPolygons(visibleTasks);
   440→  const conflictGlows = generateConflictGlows(visibleTasks);
   441→  const focusRing = generateFocusRing(visibleTasks, focusedTaskId);
   442→  const taskLabels = showLabels ? generateTaskLabels(visibleTasks, linearZoom) : [];
   443→  const dependencyPaths = generateDependencyPaths(visibleTasks);
   444→
   445→  const layers: Layer[] = [];
   446→
   447→  // Layer 1: Row backgrounds (bottom)
   448→  layers.push(
   449→    new SolidPolygonLayer<RowBackground>({
   450→      id: 'micro-row-backgrounds',
   451→      data: rowBackgrounds,
   452→      getPolygon: (d) => d.polygon,
   453→      getFillColor: (d) =>
   454→        applyOpacity(d.isEven ? ROW_BG_EVEN : ROW_BG_ODD, opacity),
   455→      pickable: false,
   456→      updateTriggers: {
   457→        getFillColor: [opacity],
   458→      },
   459→    })
   460→  );
   461→
   462→  // Layer 2: Grid lines
   463→  if (hGridLines.length > 0 || vGridLines.length > 0) {
   464→    const allGridLines = [...hGridLines, ...vGridLines];
   465→    layers.push(
   466→      new PathLayer<GridLine>({
   467→        id: 'micro-grid-lines',
   468→        data: allGridLines,
   469→        getPath: (d) => d.path,
   470→        getColor: (d) =>
   471→          applyOpacity(d.isMajor ? GRID_COLOR_MAJOR : GRID_COLOR_MINOR, opacity),
   472→        getWidth: (d) => (d.isMajor ? 1.5 : 1),
   473→        widthUnits: 'pixels',
   474→        pickable: false,
   475→        updateTriggers: {
   476→          getColor: [opacity],
   477→        },
   478→      })
   479→    );
   480→  }
   481→
   482→  // Layer 3: Conflict glows
   483→  if (conflictGlows.length > 0) {
   484→    layers.push(
   485→      new SolidPolygonLayer<EffectPolygon>({
   486→        id: 'micro-conflict-glows',
   487→        data: conflictGlows,
   488→        getPolygon: (d) => d.polygon,
   489→        getFillColor: applyOpacity([239, 68, 68, 76], opacity),
   490→        pickable: false,
   491→        updateTriggers: {
   492→          getFillColor: [opacity],
   493→        },
   494→      })
   495→    );
   496→  }
   497→
   498→  // Layer 4: Focus ring
   499→  if (focusRing) {
   500→    layers.push(
   501→      new SolidPolygonLayer<EffectPolygon>({
   502→        id: 'micro-focus-ring',
   503→        data: [focusRing],
   504→        getPolygon: (d) => d.polygon,
   505→        getFillColor: applyOpacity([139, 92, 246, 102], opacity),
   506→        pickable: false,
   507→        updateTriggers: {
   508→          getFillColor: [opacity],
   509→        },
   510→      })
   511→    );
   512→  }
   513→
   514→  // Layer 5: Task cards (pickable)
   515→  layers.push(
   516→    new SolidPolygonLayer<TaskPolygon>({
   517→      id: 'micro-task-cards',
   518→      data: taskPolygons,
   519→      getPolygon: (d) => d.polygon,
   520→      getFillColor: (d) => {
   521→        const { task } = d;
   522→        const isSelected = task.id === selectedTaskId;
   523→        const isFocused = task.id === focusedTaskId;
   524→        const isHovered = task.id === hoveredTaskId;
   525→
   526→        let color: [number, number, number, number];
   527→
   528→        if (isSelected) {
   529→          color = SELECTION_COLOR;
   530→        } else if (isFocused) {
   531→          color = FOCUS_COLOR;
   532→        } else if (task.hasConflict) {
   533→          color = isHovered ? brightenColor(CONFLICT_COLOR, 1.3) : CONFLICT_COLOR;
   534→        } else {
   535→          const baseColor = COLORS[task.color] || COLORS.gray;
   536→          color = isHovered ? brightenColor(baseColor, 1.3) : baseColor;
   537→        }
   538→
   539→        return applyOpacity(color, opacity);
   540→      },
   541→      pickable: true,
   542→      updateTriggers: {
   543→        getFillColor: [opacity, hoveredTaskId, selectedTaskId, focusedTaskId],
   544→      },
   545→    })
   546→  );
   547→
   548→  // Layer 6: Task labels
   549→  if (taskLabels.length > 0) {
   550→    layers.push(
   551→      new TextLayer<TaskLabel>({
   552→        id: 'micro-task-labels',
   553→        data: taskLabels,
   554→        getPosition: (d) => d.position,
   555→        getText: (d) => d.text,
   556→        getSize: 10,
   557→        getColor: applyOpacity([255, 255, 255, 255], opacity),
   558→        getTextAnchor: 'middle',
   559→        getAlignmentBaseline: 'center',
   560→        fontFamily: 'system-ui, -apple-system, sans-serif',
   561→        fontWeight: 'bold',
   562→        pickable: false,
   563→        updateTriggers: {
   564→          getColor: [opacity],
   565→        },
   566→      })
   567→    );
   568→  }
   569→
   570→  // Layer 7: Dependency lines
   571→  if (dependencyPaths.length > 0 && opacity >= 0.3) {
   572→    layers.push(
   573→      new PathLayer<DependencyPath>({
   574→        id: 'micro-dependency-lines',
   575→        data: dependencyPaths,
   576→        getPath: (d) => d.path,
   577→        getColor: applyOpacity(DEPENDENCY_LINE_COLOR, opacity),
   578→        getWidth: 2,
   579→        widthUnits: 'pixels',
   580→        pickable: false,
   581→        updateTriggers: {
   582→          getColor: [opacity],
   583→        },
   584→      })
   585→    );
   586→  }
   587→
   588→  return layers;
   589→}
   590→
   591→/**
   592→ * Export constants for use in other modules
   593→ */
   594→export const MICRO_CONSTANTS = {
   595→  CARD_PADDING,
   596→  CARD_HEIGHT,
   597→  COLORS,
   598→  CONFLICT_COLOR,
   599→  SELECTION_COLOR,
   600→  FOCUS_COLOR,
   601→};
