     1→/**
     2→ * TimelineHeader - Displays date labels synced with canvas panX
     3→ *
     4→ * Features:
     5→ * - Adaptive granularity based on zoom level:
     6→ *   - Low zoom (< 0.5): Years
     7→ *   - Medium zoom (0.5-1.5): Months
     8→ *   - High zoom (1.5-3.0): Weeks
     9→ *   - Very high zoom (> 3.0): Days
    10→ * - Labels positioned to align with canvas content
    11→ * - Labels don't overlap (spacing adjusted based on zoom)
    12→ *
    13→ * D3-MIGRATE-001: Uses d3-time and d3-time-format for date operations
    14→ */
    15→
    16→import { useMemo } from 'react';
    17→import { timeYear, timeMonth, timeWeek, timeDay } from 'd3-time';
    18→import { timeFormat } from 'd3-time-format';
    19→import { DEFAULT_VIEW_CONFIG, DEFAULT_DATASET_META } from '../data/types';
    20→
    21→interface TimelineHeaderProps {
    22→  /** Left edge of the visible viewport in world X coordinates */
    23→  viewportLeftX: number;
    24→  /** Right edge of the visible viewport in world X coordinates */
    25→  viewportRightX: number;
    26→  /** Current zoom level */
    27→  zoom: number;
    28→  /** Width of the sidebar (to offset the timeline) */
    29→  sidebarWidth: number;
    30→  /** Callback when a date label is clicked (F124: navigation) */
    31→  onDateClick?: (dayOffset: number) => void;
    32→}
    33→
    34→const { pxPerDay } = DEFAULT_VIEW_CONFIG;
    35→const START_DATE = new Date(DEFAULT_DATASET_META.startDate);
    36→
    37→// D3-MIGRATE-001: Format helpers using d3-time-format
    38→const formatYear = timeFormat('%Y');
    39→const formatMonth = timeFormat('%b %Y');
    40→const formatWeek = timeFormat('%b %d');
    41→const formatDay = timeFormat('%a, %b %d');
    42→
    43→/**
    44→ * Calculate the appropriate granularity based on zoom level
    45→ */
    46→type Granularity = 'year' | 'month' | 'week' | 'day';
    47→
    48→function getGranularity(zoom: number): Granularity {
    49→  if (zoom < 0.5) return 'year';
    50→  if (zoom < 1.5) return 'month';
    51→  if (zoom < 3.0) return 'week';
    52→  return 'day';
    53→}
    54→
    55→/**
    56→ * Convert world X coordinate to day offset from start date
    57→ */
    58→function worldXToDayOffset(worldX: number): number {
    59→  return Math.floor(worldX / pxPerDay);
    60→}
    61→
    62→/**
    63→ * Convert day offset to world X coordinate
    64→ */
    65→function dayOffsetToWorldX(dayOffset: number): number {
    66→  return dayOffset * pxPerDay;
    67→}
    68→
    69→// D3-MIGRATE-001: Time interval map for granularity-based operations
    70→const timeIntervals = {
    71→  year: timeYear,
    72→  month: timeMonth,
    73→  week: timeWeek,
    74→  day: timeDay,
    75→} as const;
    76→
    77→/**
    78→ * Add days to a date (D3-MIGRATE-001: uses d3-time)
    79→ */
    80→function addDays(date: Date, days: number): Date {
    81→  return timeDay.offset(date, days);
    82→}
    83→
    84→/**
    85→ * Get the start of a time unit (D3-MIGRATE-001: uses d3-time floor)
    86→ */
    87→function getUnitStart(date: Date, granularity: Granularity): Date {
    88→  return timeIntervals[granularity].floor(date);
    89→}
    90→
    91→/**
    92→ * Get days until next unit
    93→ */
    94→function getDaysPerUnit(granularity: Granularity): number {
    95→  switch (granularity) {
    96→    case 'year':
    97→      return 365;
    98→    case 'month':
    99→      return 30;
   100→    case 'week':
   101→      return 7;
   102→    case 'day':
   103→      return 1;
   104→  }
   105→}
   106→
   107→/**
   108→ * Advance to next unit (D3-MIGRATE-001: uses d3-time offset)
   109→ */
   110→function advanceUnit(date: Date, granularity: Granularity): Date {
   111→  return timeIntervals[granularity].offset(date, 1);
   112→}
   113→
   114→/**
   115→ * Format date based on granularity
   116→ */
   117→function formatDate(date: Date, granularity: Granularity): string {
   118→  switch (granularity) {
   119→    case 'year':
   120→      return formatYear(date);
   121→    case 'month':
   122→      return formatMonth(date);
   123→    case 'week':
   124→      return formatWeek(date);
   125→    case 'day':
   126→      return formatDay(date);
   127→  }
   128→}
   129→
   130→interface TimeLabel {
   131→  dayOffset: number;
   132→  worldX: number;
   133→  label: string;
   134→  isMinor: boolean; // For smaller tick marks
   135→}
   136→
   137→/**
   138→ * Generate labels for the visible viewport
   139→ */
   140→function generateLabels(
   141→  viewportLeftX: number,
   142→  viewportRightX: number,
   143→  granularity: Granularity
   144→): TimeLabel[] {
   145→  const labels: TimeLabel[] = [];
   146→
   147→  // Add padding to viewport to show labels near edges
   148→  const padding = getDaysPerUnit(granularity) * pxPerDay * 2;
   149→  const startDayOffset = worldXToDayOffset(viewportLeftX - padding);
   150→  const endDayOffset = worldXToDayOffset(viewportRightX + padding);
   151→
   152→  // Convert to dates
   153→  const startDate = addDays(START_DATE, startDayOffset);
   154→  const endDate = addDays(START_DATE, endDayOffset);
   155→
   156→  // Find the first unit boundary at or before startDate
   157→  let currentDate = getUnitStart(startDate, granularity);
   158→
   159→  // If currentDate is before START_DATE, advance to START_DATE
   160→  if (currentDate < START_DATE) {
   161→    currentDate = getUnitStart(START_DATE, granularity);
   162→    if (currentDate < START_DATE) {
   163→      currentDate = advanceUnit(currentDate, granularity);
   164→    }
   165→  }
   166→
   167→  // Generate labels until we pass endDate
   168→  while (currentDate <= endDate) {
   169→    const dayOffset = Math.round(
   170→      (currentDate.getTime() - START_DATE.getTime()) / (1000 * 60 * 60 * 24)
   171→    );
   172→    const worldX = dayOffsetToWorldX(dayOffset);
   173→
   174→    // Only add labels within reasonable range
   175→    if (worldX >= viewportLeftX - padding && worldX <= viewportRightX + padding) {
   176→      labels.push({
   177→        dayOffset,
   178→        worldX,
   179→        label: formatDate(currentDate, granularity),
   180→        isMinor: false,
   181→      });
   182→    }
   183→
   184→    currentDate = advanceUnit(currentDate, granularity);
   185→  }
   186→
   187→  return labels;
   188→}
   189→
   190→export function TimelineHeader({
   191→  viewportLeftX,
   192→  viewportRightX,
   193→  zoom,
   194→  sidebarWidth,
   195→  onDateClick,
   196→}: TimelineHeaderProps) {
   197→  const granularity = useMemo(() => getGranularity(zoom), [zoom]);
   198→
   199→  const labels = useMemo(
   200→    () => generateLabels(viewportLeftX, viewportRightX, granularity),
   201→    [viewportLeftX, viewportRightX, granularity]
   202→  );
   203→
   204→  // Calculate viewport width with defensive check
   205→  const viewportWidth = viewportRightX - viewportLeftX;
   206→
   207→  // BUG-005: Guard against invalid viewport (e.g., during initialization)
   208→  const isViewportValid = isFinite(viewportWidth) && viewportWidth > 0;
   209→
   210→  return (
   211→    <div
   212→      style={{
   213→        height: 32,
   214→        backgroundColor: '#f5f8fa',
   215→        borderBottom: '1px solid #e1e8ed',
   216→        display: 'flex',
   217→        alignItems: 'center',
   218→        overflow: 'hidden',
   219→        position: 'relative',
   220→        marginLeft: sidebarWidth,
   221→      }}
   222→    >
   223→      {isViewportValid && labels.map((label, index) => {
   224→        // Calculate position as percentage of viewport
   225→        const positionInViewport = label.worldX - viewportLeftX;
   226→        const percentPosition = (positionInViewport / viewportWidth) * 100;
   227→
   228→        // BUG-005: Skip labels that would be too far off screen
   229→        // Use wider bounds for year granularity since labels are spaced far apart
   230→        const skipMargin = granularity === 'year' ? 50 : 20;
   231→        if (!isFinite(percentPosition) || percentPosition < -skipMargin || percentPosition > 100 + skipMargin) {
   232→          return null;
   233→        }
   234→
   235→        // BUG-005: Adjust transform for edge labels to keep them visible
   236→        // At edges, don't center the label - align it to stay within bounds
   237→        let transformX = '-50%';  // Default: center on position
   238→        if (percentPosition < 5) {
   239→          // Near left edge: align left edge to position
   240→          transformX = '0%';
   241→        } else if (percentPosition > 95) {
   242→          // Near right edge: align right edge to position
   243→          transformX = '-100%';
   244→        }
   245→
   246→        return (
   247→          <div
   248→            key={`${label.label}-${index}`}
   249→            onClick={() => onDateClick?.(label.dayOffset)}
   250→            style={{
   251→              position: 'absolute',
   252→              left: `${percentPosition}%`,
   253→              transform: `translateX(${transformX})`,
   254→              fontSize: 11,
   255→              fontFamily: 'monospace',
   256→              color: '#5c7080',
   257→              whiteSpace: 'nowrap',
   258→              padding: '4px 8px',
   259→              display: 'flex',
   260→              flexDirection: 'column',
   261→              alignItems: 'center',
   262→              cursor: onDateClick ? 'pointer' : 'default',
   263→              borderRadius: 4,
   264→              transition: 'background-color 0.15s ease, color 0.15s ease',
   265→              zIndex: 2, // BUG-005: Ensure labels are above gradient overlays
   266→              backgroundColor: '#f5f8fa', // BUG-005: Add background so labels are readable over gradients
   267→            }}
   268→            onMouseEnter={(e) => {
   269→              if (onDateClick) {
   270→                e.currentTarget.style.backgroundColor = '#e1e8ed';
   271→                e.currentTarget.style.color = '#1c2127';
   272→              }
   273→            }}
   274→            onMouseLeave={(e) => {
   275→              e.currentTarget.style.backgroundColor = 'transparent';
   276→              e.currentTarget.style.color = '#5c7080';
   277→            }}
   278→            title={onDateClick ? `Click to navigate to ${label.label}` : undefined}
   279→          >
   280→            <span>{label.label}</span>
   281→            <div
   282→              style={{
   283→                width: 1,
   284→                height: 6,
   285→                backgroundColor: '#d8e1e8',
   286→                marginTop: 2,
   287→              }}
   288→            />
   289→          </div>
   290→        );
   291→      })}
   292→
   293→      {/* Gradient overlays to fade labels at edges - z-index 1 so labels (z-index 2) are above */}
   294→      <div
   295→        style={{
   296→          position: 'absolute',
   297→          left: 0,
   298→          top: 0,
   299→          bottom: 0,
   300→          width: 20, // BUG-005: Reduced from 30 to leave more space for labels
   301→          background: 'linear-gradient(to right, #f5f8fa, transparent)',
   302→          pointerEvents: 'none',
   303→          zIndex: 1,
   304→        }}
   305→      />
   306→      <div
   307→        style={{
   308→          position: 'absolute',
   309→          right: 0,
   310→          top: 0,
   311→          bottom: 0,
   312→          width: 20, // BUG-005: Reduced from 30 to leave more space for labels
   313→          background: 'linear-gradient(to left, #f5f8fa, transparent)',
   314→          pointerEvents: 'none',
   315→          zIndex: 1,
   316→        }}
   317→      />
   318→    </div>
   319→  );
   320→}
   321→

