/**
 * TaskTooltip Component (F020)
 *
 * Shows task details on hover near the cursor position.
 * Uses BlueprintJS styling for consistency.
 *
 * Displays:
 * - Task type (maintenance/overhaul/inspection)
 * - Date range (start - end)
 * - Train ID
 * - Conflict status (if applicable)
 * - Duration in days
 */

import { useMemo } from 'react';
import { Tag, Intent, Icon } from '@blueprintjs/core';
import type { IconName } from '@blueprintjs/icons';
import { getData } from '../data/generator';
import type { TaskType } from '../data/types';

// ─────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────

interface TaskTooltipProps {
  /** ID of the hovered task (null = hidden) */
  taskId: string | null;
  /** Mouse X position in viewport pixels */
  mouseX: number;
  /** Mouse Y position in viewport pixels */
  mouseY: number;
}

// ─────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────

/**
 * Get intent color for task type
 */
function getTypeIntent(type: TaskType): Intent {
  switch (type) {
    case 'maintenance':
      return Intent.PRIMARY;
    case 'overhaul':
      return Intent.WARNING;
    case 'inspection':
      return Intent.NONE;
  }
}

/**
 * Get icon for task type
 */
function getTypeIcon(type: TaskType): IconName {
  switch (type) {
    case 'maintenance':
      return 'wrench';
    case 'overhaul':
      return 'build';
    case 'inspection':
      return 'eye-open';
  }
}

/**
 * Format date for display (e.g., "Mar 15, 2024")
 */
function formatDate(isoDate: string): string {
  const date = new Date(isoDate);
  return date.toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

/**
 * Calculate duration in days from ISO dates
 */
function calculateDuration(startDate: string, endDate: string): number {
  const start = new Date(startDate);
  const end = new Date(endDate);
  const diffTime = end.getTime() - start.getTime();
  return Math.round(diffTime / (1000 * 60 * 60 * 24));
}

/**
 * Capitalize first letter
 */
function capitalize(str: string): string {
  return str.charAt(0).toUpperCase() + str.slice(1);
}

// ─────────────────────────────────────────────────────────────
// COMPONENT
// ─────────────────────────────────────────────────────────────

export function TaskTooltip({ taskId, mouseX, mouseY }: TaskTooltipProps) {
  // Get original task data (with dates as strings)
  const taskData = useMemo(() => {
    if (!taskId) return null;

    const data = getData();
    const task = data.tasks.find((t) => t.id === taskId);
    if (!task) return null;

    const train = data.trains.find((t) => t.id === task.trainId);
    const duration = calculateDuration(task.startDate, task.endDate);

    return {
      id: task.id,
      trainId: task.trainId,
      trainName: train?.name || task.trainId,
      type: task.type,
      startDate: task.startDate,
      endDate: task.endDate,
      duration,
      hasConflict: task.hasConflict,
    };
  }, [taskId]);

  // Don't render if no task
  if (!taskData) return null;

  // Position tooltip near cursor with offset
  // Offset to bottom-right of cursor, with boundary checks
  const OFFSET_X = 16;
  const OFFSET_Y = 16;
  const TOOLTIP_WIDTH = 220;
  const TOOLTIP_HEIGHT = 140;

  // Adjust position to stay within viewport
  let left = mouseX + OFFSET_X;
  let top = mouseY + OFFSET_Y;

  // Check right edge
  if (left + TOOLTIP_WIDTH > window.innerWidth - 20) {
    left = mouseX - TOOLTIP_WIDTH - OFFSET_X;
  }

  // Check bottom edge
  if (top + TOOLTIP_HEIGHT > window.innerHeight - 20) {
    top = mouseY - TOOLTIP_HEIGHT - OFFSET_Y;
  }

  // Ensure minimum position
  left = Math.max(10, left);
  top = Math.max(10, top);

  return (
    <div
      style={{
        position: 'fixed',
        left,
        top,
        zIndex: 1000,
        pointerEvents: 'none',
        // BlueprintJS-style tooltip appearance
        backgroundColor: '#394b59',
        color: '#f5f8fa',
        borderRadius: 3,
        boxShadow: '0 2px 10px rgba(0, 0, 0, 0.3)',
        padding: '10px 12px',
        fontSize: 12,
        lineHeight: 1.5,
        minWidth: 180,
        maxWidth: TOOLTIP_WIDTH,
      }}
    >
      {/* Task type header */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 8,
          marginBottom: 8,
          paddingBottom: 8,
          borderBottom: '1px solid rgba(255, 255, 255, 0.2)',
        }}
      >
        <Icon icon={getTypeIcon(taskData.type)} size={14} />
        <Tag intent={getTypeIntent(taskData.type)} minimal>
          {capitalize(taskData.type)}
        </Tag>
        {taskData.hasConflict && (
          <Tag intent={Intent.DANGER} minimal icon="warning-sign">
            Conflict
          </Tag>
        )}
      </div>

      {/* Task details */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
        {/* Train ID */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
          <Icon icon="train" size={12} style={{ opacity: 0.7 }} />
          <span style={{ fontFamily: 'monospace', fontWeight: 500 }}>
            {taskData.trainId}
          </span>
        </div>

        {/* Date range */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
          <Icon icon="calendar" size={12} style={{ opacity: 0.7 }} />
          <span>
            {formatDate(taskData.startDate)} — {formatDate(taskData.endDate)}
          </span>
        </div>

        {/* Duration */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
          <Icon icon="time" size={12} style={{ opacity: 0.7 }} />
          <span>
            {taskData.duration} day{taskData.duration !== 1 ? 's' : ''}
          </span>
        </div>
      </div>
    </div>
  );
}

