/**
 * TaskDetailsPanel Component (F026)
 *
 * Shows detailed task information in a side panel when a task is selected.
 * Uses BlueprintJS Drawer for the panel.
 *
 * Features:
 * - Opens when a task is selected
 * - Displays comprehensive task information
 * - Closes on deselect or close button click
 * - Shows conflict status with visual indicator
 */

import { useMemo, useCallback } from 'react';
import {
  Drawer,
  DrawerSize,
  Button,
  Tag,
  Intent,
  Icon,
  Divider,
  H4,
  H5,
  Classes,
} from '@blueprintjs/core';
import type { IconName } from '@blueprintjs/icons';
import { getData } from '../data/generator';
import { useCanvasSelector, canvasStore, canvasActions } from '../state';
import type { TaskType, AssetType } from '../data/types';

// ─────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────

/**
 * Get intent color for task type
 */
function getTypeIntent(type: TaskType): Intent {
  switch (type) {
    case 'maintenance':
      return Intent.PRIMARY;
    case 'overhaul':
      return Intent.WARNING;
    case 'inspection':
      return Intent.NONE;
  }
}

/**
 * Get icon for task type
 */
function getTypeIcon(type: TaskType): IconName {
  switch (type) {
    case 'maintenance':
      return 'wrench';
    case 'overhaul':
      return 'build';
    case 'inspection':
      return 'eye-open';
  }
}

/**
 * Get icon for asset type (train fleet)
 */
function getAssetIcon(_assetType: AssetType): IconName {
  // Both fleets use 'train' icon (BlueprintJS doesn't have a tram icon)
  return 'train';
}

/**
 * Format date for display (e.g., "Mar 15, 2024")
 */
function formatDate(isoDate: string): string {
  const date = new Date(isoDate);
  return date.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
}

/**
 * Calculate duration in days from ISO dates
 */
function calculateDuration(startDate: string, endDate: string): number {
  const start = new Date(startDate);
  const end = new Date(endDate);
  const diffTime = end.getTime() - start.getTime();
  return Math.round(diffTime / (1000 * 60 * 60 * 24));
}

/**
 * Capitalize first letter
 */
function capitalize(str: string): string {
  return str.charAt(0).toUpperCase() + str.slice(1);
}

